-- Esquema de Base de Datos Relacional


CREATE TABLE provincias (
    provincia_id INT PRIMARY KEY,
    nombre VARCHAR(255)
);

CREATE TABLE departamentos (
    departamento_id INT PRIMARY KEY,
    nombre VARCHAR(255),
    provincia_id INT REFERENCES provincias(provincia_id)
);

CREATE TABLE localidades (
    localidad_id VARCHAR(8) PRIMARY KEY,
    nombre VARCHAR(255),
    departamento_id INT REFERENCES departamentos(departamento_id)
);

CREATE TABLE produccion (
    id SERIAL PRIMARY KEY,
    año INT,
    localidad_id VARCHAR(8) REFERENCES localidades(localidad_id),
    tipo_establecimiento VARCHAR(255),
    tipo_producto VARCHAR(255),
    codigo_producto VARCHAR(100),
    color VARCHAR(100),
    litros INT
);

